const fetch = require('node-fetch');

const baseUrl = String($baseUrl || 'https://bilig.proompteng.ai').replace(/\/$/, '');
const sheetName = String($sheetName || 'Inputs');
const address = String($address || 'B3').toUpperCase();
const value = $value == null || $value === '' ? 0.4 : Number($value);

if (!baseUrl.startsWith('http://') && !baseUrl.startsWith('https://')) {
    return 'Bilig WorkPaper formula readback failed: baseUrl must start with http:// or https://';
}

if (!Number.isFinite(value)) {
    return `Bilig WorkPaper formula readback failed: value must be numeric, received ${JSON.stringify($value)}`;
}

const response = await fetch(`${baseUrl}/api/workpaper/n8n/forecast`, {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'User-Agent': 'Flowise-Bilig-WorkPaper-Tool/0.1'
    },
    body: JSON.stringify({ sheetName, address, value })
});

const text = await response.text();
let proof;
try {
    proof = JSON.parse(text);
} catch (error) {
    return `Bilig WorkPaper formula readback failed: expected JSON but received ${text.slice(0, 500)}`;
}

if (proof == null || typeof proof !== 'object' || Array.isArray(proof)) {
    return `Bilig WorkPaper formula readback failed: expected JSON object response, received ${Array.isArray(proof) ? 'array' : typeof proof}`;
}

if (!response.ok) {
    return `Bilig WorkPaper formula readback failed: HTTP ${response.status} ${response.statusText} - ${JSON.stringify(proof)}`;
}

if (proof.verified !== true) {
    const proofId = proof.workpaper_id || proof.id || 'unknown';
    return `Bilig WorkPaper formula readback failed: unverified response (verified=${proof.verified}) for workpaper_id=${proofId}`;
}

const checks = proof.checks && typeof proof.checks === 'object' && !Array.isArray(proof.checks) ? proof.checks : {};
const before = proof.before && typeof proof.before === 'object' && !Array.isArray(proof.before) ? proof.before : {};
const after = proof.after && typeof proof.after === 'object' && !Array.isArray(proof.after) ? proof.after : {};
const compactProof = {
    verified: true,
    editedCell: proof.editedCell,
    before: {
        expectedArr: before.expectedArr,
        targetGap: before.targetGap
    },
    after: {
        expectedArr: after.expectedArr,
        targetGap: after.targetGap
    },
    checks: {
        formulasPersisted: checks.formulasPersisted === true,
        restoredMatchesAfter: checks.restoredMatchesAfter === true,
        computedOutputChanged: checks.computedOutputChanged === true
    },
    source: 'Bilig WorkPaper',
    github: 'https://github.com/proompteng/bilig'
};

return JSON.stringify(compactProof, null, 2);
